11	
12	type ConfigRepository struct {
13		db *pgxpool.Pool
14	}
15	
16	func NewConfigRepository(db *pgxpool.Pool) *ConfigRepository {
17		return &ConfigRepository{db: db}
18	}
19	
20	func (r *ConfigRepository) GetAllConfigs(ctx context.Context) ([]models.Config, error) {
21		rows, err := r.db.Query(ctx, `
22			SELECT id, key, value, value_type, COALESCE(module, ''),
23				   COALESCE(description, ''), updated_by, created_at, updated_at
24			FROM configs ORDER BY module, key
25		`)
26		if err != nil {
27			return nil, err
28		}
29		defer rows.Close()
30	
31		configs := make([]models.Config, 0)
32		for rows.Next() {
33			var c models.Config
34			if err := rows.Scan(&c.ID, &c.Key, &c.Value, &c.ValueType,
35				&c.Module, &c.Description, &c.UpdatedBy, &c.CreatedAt, &c.UpdatedAt); err != nil {
36				return nil, err
37			}
38			configs = append(configs, c)
39		}
40		return configs, rows.Err()
41	}
42	
43	func (r *ConfigRepository) GetConfigByKey(ctx context.Context, key string) (*models.Config, error) {
44		c := &models.Config{}
45		err := r.db.QueryRow(ctx, `
46			SELECT id, key, value, value_type, COALESCE(module, ''),
47				   COALESCE(description, ''), updated_by, created_at, updated_at
48			FROM configs WHERE key = $1
49		`, key).Scan(&c.ID, &c.Key, &c.Value, &c.ValueType,
50			&c.Module, &c.Description, &c.UpdatedBy, &c.CreatedAt, &c.UpdatedAt)
51		if err == pgx.ErrNoRows {
52			return nil, nil
53		}
54		return c, err
55	}
56	
57	func (r *ConfigRepository) UpdateConfig(ctx context.Context, key, value string, updatedBy int) error {
58		_, err := r.db.Exec(ctx, `
59			UPDATE configs SET value = $2, updated_by = $3, updated_at = NOW()
60			WHERE key = $1
61		`, key, value, updatedBy)
62		return err
63	}
64	
65	func (r *ConfigRepository) GetAllFeatureFlags(ctx context.Context) ([]models.FeatureFlag, error) {
66		rows, err := r.db.Query(ctx, `
67			SELECT id, key, COALESCE(description, ''), enabled, rollout_strategy,
68				   rollout_percentage, allowed_roles, created_by, created_at, updated_at
69			FROM feature_flags ORDER BY key
70		`)
71		if err != nil {
72			return nil, err
73		}
74		defer rows.Close()
75	
76		flags := make([]models.FeatureFlag, 0)
77		for rows.Next() {
78			var f models.FeatureFlag
79			if err := rows.Scan(&f.ID, &f.Key, &f.Description, &f.Enabled,
80				&f.RolloutStrategy, &f.RolloutPercentage, &f.AllowedRoles,
81				&f.CreatedBy, &f.CreatedAt, &f.UpdatedAt); err != nil {
82				return nil, err
83			}
84			flags = append(flags, f)
85		}
86		return flags, rows.Err()
87	}
88	
89	func (r *ConfigRepository) GetFeatureFlag(ctx context.Context, key string) (*models.FeatureFlag, error) {
90		f := &models.FeatureFlag{}
91		err := r.db.QueryRow(ctx, `
92			SELECT id, key, COALESCE(description, ''), enabled, rollout_strategy,
93				   rollout_percentage, allowed_roles, created_by, created_at, updated_at
94			FROM feature_flags WHERE key = $1
95		`, key).Scan(&f.ID, &f.Key, &f.Description, &f.Enabled,
96			&f.RolloutStrategy, &f.RolloutPercentage, &f.AllowedRoles,
97			&f.CreatedBy, &f.CreatedAt, &f.UpdatedAt)
98		if err == pgx.ErrNoRows {
99			return nil, nil
100		}
101		return f, err
102	}
103	
104	func (r *ConfigRepository) UpdateFeatureFlag(ctx context.Context, key string, req models.FeatureFlagUpdateRequest) error {
105		if req.Enabled != nil {
106			if _, err := r.db.Exec(ctx, `
107				UPDATE feature_flags SET enabled = $2, updated_at = NOW() WHERE key = $1
108			`, key, *req.Enabled); err != nil {
109				return err
110			}
111		}
112		if req.RolloutStrategy != "" {
113			if _, err := r.db.Exec(ctx, `
114				UPDATE feature_flags SET rollout_strategy = $2, updated_at = NOW() WHERE key = $1
115			`, key, req.RolloutStrategy); err != nil {
116				return err
117			}
118		}
119		if req.RolloutPercentage != nil {
120			if _, err := r.db.Exec(ctx, `
121				UPDATE feature_flags SET rollout_percentage = $2, updated_at = NOW() WHERE key = $1
122			`, key, *req.RolloutPercentage); err != nil {
123				return err
124			}
125		}
126		if req.AllowedRoles != nil {
127			if _, err := r.db.Exec(ctx, `
128				UPDATE feature_flags SET allowed_roles = $2, updated_at = NOW() WHERE key = $1
129			`, key, req.AllowedRoles); err != nil {
130				return err
131			}
132		}
133		return nil
134	}
