22	func (r *TaxonomyRepository) GetAllTags(ctx context.Context, tagType string) ([]models.TaxonomyTag, error) {
23		query := `
24			SELECT id, name, slug, tag_type, parent_id, canonical_id, pinyin,
25				   description, is_canonical, level, sort_order, usage_count,
26				   created_at, updated_at
27			FROM taxonomy_tags
28		`
29		args := []interface{}{}
30		if tagType != "" {
31			query += " WHERE tag_type = $1"
32			args = append(args, tagType)
33		}
34		query += " ORDER BY level, sort_order, name"
35	
36		rows, err := r.db.Query(ctx, query, args...)
37		if err != nil {
38			return nil, err
39		}
40		defer rows.Close()
41		return scanTags(rows)
42	}
