47			SELECT id, name, slug, tag_type, parent_id, canonical_id, pinyin,
48				   description, is_canonical, level, sort_order, usage_count,
49				   created_at, updated_at
50			FROM taxonomy_tags WHERE id = $1
51		`, id).Scan(
52			&tag.ID, &tag.Name, &tag.Slug, &tag.TagType, &tag.ParentID,
53			&tag.CanonicalID, &tag.Pinyin, &tag.Description, &tag.IsCanonical,
