63	func (r *TaxonomyRepository) GetTagChildren(ctx context.Context, parentID int) ([]models.TaxonomyTag, error) {
64		rows, err := r.db.Query(ctx, `
65			SELECT id, name, slug, tag_type, parent_id, canonical_id, pinyin,
66				   description, is_canonical, level, sort_order, usage_count,
67				   created_at, updated_at
68			FROM taxonomy_tags WHERE parent_id = $1
69			ORDER BY sort_order, name
70		`, parentID)
71		if err != nil {
72			return nil, err
73		}
74		defer rows.Close()
75		return scanTags(rows)
76	}
77	
78	func (r *TaxonomyRepository) GetTagHierarchy(ctx context.Context, tagType string) ([]models.TaxonomyTag, error) {
79		// Get all root-level tags
80		query := `
81			SELECT id, name, slug, tag_type, parent_id, canonical_id, pinyin,
82				   description, is_canonical, level, sort_order, usage_count,
83				   created_at, updated_at
84			FROM taxonomy_tags WHERE parent_id IS NULL
85		`
86		args := []interface{}{}
87		if tagType != "" {
88			query += " AND tag_type = $1"
89			args = append(args, tagType)
90		}
91		query += " ORDER BY sort_order, name"
92	
93		rows, err := r.db.Query(ctx, query, args...)
94		if err != nil {
95			return nil, err
96		}
97		defer rows.Close()
98	
99		roots, err := scanTags(rows)
100		if err != nil {
101			return nil, err
102		}
103	
104		// Recursively load children
105		for i := range roots {
106			if err := r.loadChildren(ctx, &roots[i]); err != nil {
107				return nil, err
108			}
109		}
110		return roots, nil
111	}
112	
113	func (r *TaxonomyRepository) loadChildren(ctx context.Context, tag *models.TaxonomyTag) error {
114		children, err := r.GetTagChildren(ctx, tag.ID)
115		if err != nil {
116			return err
117		}
118		tag.Children = children
119		for i := range tag.Children {
120			if err := r.loadChildren(ctx, &tag.Children[i]); err != nil {
121				return err
122			}
123		}
124		return nil
125	}
126	
127	func (r *TaxonomyRepository) CreateTag(ctx context.Context, req models.CreateTagRequest, createdBy int) (*models.TaxonomyTag, error) {
128		slug := slugify(req.Name)
129	
130		var level int
131		if req.ParentID != nil {
132			var parentLevel int
133			err := r.db.QueryRow(ctx, "SELECT level FROM taxonomy_tags WHERE id = $1", *req.ParentID).Scan(&parentLevel)
134			if err != nil {
135				return nil, fmt.Errorf("parent tag not found")
136			}
137			level = parentLevel + 1
138		}
139	
140		tag := &models.TaxonomyTag{}
141		err := r.db.QueryRow(ctx, `
142			INSERT INTO taxonomy_tags (name, slug, tag_type, parent_id, pinyin, description, level, created_by)
143			VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
144			RETURNING id, name, slug, tag_type, parent_id, canonical_id, pinyin,
145					  description, is_canonical, level, sort_order, usage_count, created_at, updated_at
146		`, req.Name, slug, req.TagType, req.ParentID, req.Pinyin, req.Description, level, createdBy).Scan(
147			&tag.ID, &tag.Name, &tag.Slug, &tag.TagType, &tag.ParentID,
148			&tag.CanonicalID, &tag.Pinyin, &tag.Description, &tag.IsCanonical,
149			&tag.Level, &tag.SortOrder, &tag.UsageCount, &tag.CreatedAt, &tag.UpdatedAt,
150		)
151		return tag, err
152	}
