97		for i := range progress {
98			progressMap[progress[i].ResourceID] = &progress[i]
99		}
100	
101		var requiredItems, electiveItems []models.PathItemProgress
102		var requiredComplete, electiveComplete int
103	
104		for _, item := range path.Items {
