27	// SetupMFA generates a new TOTP secret, encrypts it, and stores it for the user.
28	// Returns the secret (for QR code) and provisioning URI.
29	func (s *MFAService) SetupMFA(ctx context.Context, userID int, username string) (secret string, provisioningURI string, err error) {
30		key, err := totp.Generate(totp.GenerateOpts{
31			Issuer:      "WLPR-Portal",
32			AccountName: username,
33			Period:      30,
34			SecretSize:  32,
35			Digits:      otp.DigitsSix,
36			Algorithm:   otp.AlgorithmSHA1,
37		})
38		if err != nil {
39			return "", "", fmt.Errorf("failed to generate TOTP key: %w", err)
40		}
41	
42		encSecret, err := crypto.EncryptString(key.Secret())
43		if err != nil {
44			return "", "", fmt.Errorf("failed to encrypt MFA secret: %w", err)
45		}
46	
47		if err := s.userRepo.SetMFASecret(ctx, userID, encSecret); err != nil {
48			return "", "", fmt.Errorf("failed to store MFA secret: %w", err)
49		}
50	
51		return key.Secret(), key.URL(), nil
52	}
53	
54	// ConfirmMFA validates the initial TOTP code and enables MFA, generating recovery codes.
55	func (s *MFAService) ConfirmMFA(ctx context.Context, userID int, code string) ([]string, error) {
56		user, err := s.userRepo.FindByID(ctx, userID)
57		if err != nil || user == nil {
58			return nil, fmt.Errorf("user not found")
59		}
60	
61		if user.MFASecretEnc == nil {
62			return nil, fmt.Errorf("MFA setup not initiated")
63		}
64	
65		secret, err := crypto.DecryptString(user.MFASecretEnc)
66		if err != nil {
67			return nil, fmt.Errorf("failed to decrypt MFA secret: %w", err)
68		}
69	
70		if !ValidateTOTP(secret, code) {
71			return nil, fmt.Errorf("invalid TOTP code")
72		}
73	
74		recoveryCodes := generateRecoveryCodes(8)
75	
76		recoveryJSON, _ := json.Marshal(recoveryCodes)
77		encRecovery, err := crypto.Encrypt(recoveryJSON)
78		if err != nil {
79			return nil, fmt.Errorf("failed to encrypt recovery codes: %w", err)
80		}
81	
82		if err := s.userRepo.EnableMFA(ctx, userID, encRecovery); err != nil {
83			return nil, fmt.Errorf("failed to enable MFA: %w", err)
84		}
85	
86		return recoveryCodes, nil
87	}
