94	// ValidateTOTP checks a TOTP code against a secret, allowing +-1 period skew.
95	func ValidateTOTP(secret, code string) bool {
96		valid, err := totp.ValidateCustom(code, secret, time.Now(), totp.ValidateOpts{
97			Period:    30,
98			Skew:     1,
99			Digits:   otp.DigitsSix,
100			Algorithm: otp.AlgorithmSHA1,
101		})
102		return err == nil && valid
103	}
104	
105	func generateRecoveryCodes(count int) []string {
106		codes := make([]string, count)
107		for i := 0; i < count; i++ {
108			b := make([]byte, 5)
109			_, _ = rand.Read(b)
110			raw := strings.ToUpper(base32.StdEncoding.EncodeToString(b))
111			if len(raw) > 8 {
112				raw = raw[:8]
113			}
114			codes[i] = fmt.Sprintf("%s-%s", raw[:4], raw[4:])
115		}
116		return codes
117	}
