97				}
98	
99				for _, required := range perms {
100					for _, userPerm := range userPerms {
101						if required == userPerm {
102							return next(c)
103						}
104					}
105				}
106	
107				return echo.NewHTTPError(http.StatusNotFound)
108			}
109		}
110	}
