112	// AppVersionCheck middleware checks the client's app version header and enforces compatibility.
113	// Clients below the minimum supported version enter a 14-day (configurable) read-only grace
114	// period. During grace, GET/HEAD/OPTIONS requests are allowed but writes are blocked.
115	// After the grace period expires, all requests are blocked.
116	func (m *AuthMiddleware) AppVersionCheck() echo.MiddlewareFunc {
117		return func(next echo.HandlerFunc) echo.HandlerFunc {
118			return func(c echo.Context) error {
119				clientVersion := c.Request().Header.Get("X-App-Version")
120				if clientVersion == "" {
121					return next(c) // Allow requests without version header (browser clients)
122				}
123	
124				minVersion, _ := m.configService.GetConfig("app.min_supported_version")
125				if minVersion == "" {
126					return next(c)
127				}
128	
129				if compareVersions(clientVersion, minVersion) < 0 {
130					// Determine grace period: how long the min_version has been in effect
131					graceDays := 14
132					if val, ok := m.configService.GetConfig("app.read_only_grace_days"); ok {
133						var d int
134						if _, err := fmt.Sscanf(val, "%d", &d); err == nil && d > 0 {
135							graceDays = d
136						}
137					}
138	
139					// Get the timestamp when the min_supported_version was last updated
140					// (approximated by the config's updated_at). If not available, treat
141					// as if just updated (full grace period).
142					minVersionSetAt := m.configService.GetConfigUpdatedAt("app.min_supported_version")
143	
144					graceDeadline := minVersionSetAt.Add(time.Duration(graceDays) * 24 * time.Hour)
145					withinGrace := time.Now().Before(graceDeadline)
146	
147					c.Response().Header().Set("X-App-Deprecated", "true")
148					c.Response().Header().Set("X-Min-Version", minVersion)
149	
150					if !withinGrace {
151						// Grace period expired: hard block ALL requests
152						return echo.NewHTTPError(http.StatusUpgradeRequired,
153							"client version unsupported and grace period expired; upgrade to "+minVersion+" or later")
154					}
155	
156					// Within grace period: allow read-only access
157					c.Set("read_only", true)
158					daysLeft := int(time.Until(graceDeadline).Hours() / 24)
159					c.Response().Header().Set("X-Grace-Days-Remaining", fmt.Sprintf("%d", daysLeft))
160	
161					method := c.Request().Method
162					if method == "POST" || method == "PUT" || method == "PATCH" || method == "DELETE" {
163						return echo.NewHTTPError(http.StatusUpgradeRequired,
164							fmt.Sprintf("client version unsupported; read-only access for %d more days. Upgrade to %s or later.",
165								daysLeft, minVersion))
166					}
167				}
168	
169				return next(c)
170			}
171		}
172	}
