26	// Search performs full-text search with synonym expansion, pinyin matching, and filtering.
27	func (s *SearchService) Search(ctx context.Context, req models.SearchRequest) (*models.SearchResponse, error) {
28		var synonymTagIDs []int
29		var appliedSynonyms []string
30		var pinyinQuery string
31	
32		query := strings.TrimSpace(req.Query)
33	
34		if query != "" {
35			// Synonym expansion: look up each word in the query
36			if s.configSvc.IsFlagEnabled("synonym_search", nil) {
37				words := strings.Fields(strings.ToLower(query))
38				for _, word := range words {
39					tagIDs, err := s.taxonomyRepo.FindSynonymMappings(ctx, word)
40					if err == nil && len(tagIDs) > 0 {
41						synonymTagIDs = append(synonymTagIDs, tagIDs...)
42						appliedSynonyms = append(appliedSynonyms, word)
43					}
44				}
45			}
46	
47			// Pinyin conversion for Chinese character matching
48			if s.configSvc.IsFlagEnabled("pinyin_search", nil) {
49				pinyinQuery = pinyin.ToPinyin(query)
50				// Only use pinyin if it differs from the original query
51				if pinyinQuery == strings.ToLower(query) {
52					pinyinQuery = ""
53				}
54			}
55		}
56	
57		// Deduplicate synonym tag IDs
58		synonymTagIDs = dedup(synonymTagIDs)
59	
60		resp, err := s.searchRepo.SearchResources(ctx, req, synonymTagIDs, pinyinQuery)
61		if err != nil {
62			return nil, err
63		}
64	
65		if len(appliedSynonyms) > 0 {
66			resp.Synonyms = appliedSynonyms
67		}
68	
69		return resp, nil
70	}
