292	func slugify(name string) string {
293		s := strings.ToLower(strings.TrimSpace(name))
294		s = strings.Map(func(r rune) rune {
295			if (r >= 'a' && r <= 'z') || (r >= '0' && r <= '9') || r == '-' {
296				return r
297			}
298			if r == ' ' || r == '_' {
299				return '-'
300			}
301			return -1
302		}, s)
303		// Remove consecutive dashes
304		for strings.Contains(s, "--") {
305			s = strings.ReplaceAll(s, "--", "-")
306		}
307		return strings.Trim(s, "-")
308	}
