129	// IsFlagEnabled checks if a feature flag is enabled for a given user's roles.
130	func (s *ConfigService) IsFlagEnabled(key string, userRoleIDs []int) bool {
131		s.mu.RLock()
132		defer s.mu.RUnlock()
133	
134		f, ok := s.flags[key]
135		if !ok || !f.Enabled {
136			return false
137		}
138	
139		switch f.RolloutStrategy {
140		case "all":
141			return true
142		case "disabled":
143			return false
144		case "role_based":
145			for _, allowed := range f.AllowedRoles {
146				for _, userRole := range userRoleIDs {
147					if allowed == userRole {
148						return true
149					}
150				}
151			}
152			return false
153		case "percentage":
154			// For percentage-based, we use a deterministic hash of the key
155			// In a real impl, you'd hash user_id + flag_key for consistent bucketing.
156			// For now, just check if the percentage > 0 means enabled.
157			return f.RolloutPercentage > 0
158		default:
159			return false
160		}
161	}
