87	func parseIntList(s string) []int {
88		if s == "" {
89			return nil
90		}
91		var result []int
92		for _, part := range splitComma(s) {
93			if id, err := strconv.Atoi(part); err == nil {
94				result = append(result, id)
95			}
96		}
97		return result
98	}
99	
100	func splitComma(s string) []string {
101		var parts []string
102		current := ""
103		for _, ch := range s {
104			if ch == ',' {
105				if current != "" {
106					parts = append(parts, current)
107				}
108				current = ""
109			} else {
110				current += string(ch)
111			}
112		}
113		if current != "" {
114			parts = append(parts, current)
115		}
116		return parts
117	}
