3	import (
4		"testing"
5	)
6	
7	// The synonym conflict detection is enforced by a PostgreSQL trigger (check_synonym_conflict),
8	// so the definitive test is an integration test against a real DB. However, we can validate
9	// the backend's conflict detection logic rules here as unit tests.
10	
11	// synonymConflictExists checks whether adding a new active synonym with the given term
12	// and canonical_tag_id would conflict with existing active synonyms.
13	// This mirrors the logic in the PostgreSQL trigger check_synonym_conflict().
14	func synonymConflictExists(existingSynonyms []testSynonym, newTerm string, newCanonicalID int) bool {
15		for _, existing := range existingSynonyms {
16			if existing.Status != "active" {
17				continue
18			}
19			if existing.Term == newTerm && existing.CanonicalTagID != newCanonicalID {
20				return true
21			}
22		}
23		return false
24	}
25	
26	type testSynonym struct {
27		ID             int
28		Term           string
29		CanonicalTagID int
30		Status         string
31	}
32	
33	func TestSynonymConflict_DuplicateActiveBlocksDifferentCanonical(t *testing.T) {
34		// Pre-existing: "ML" -> canonical tag 3 (Data Science), active
35		existing := []testSynonym{
36			{ID: 1, Term: "ML", CanonicalTagID: 3, Status: "active"},
37		}
38	
39		// Attempt: "ML" -> canonical tag 7 (Go) — MUST conflict
40		if !synonymConflictExists(existing, "ML", 7) {
41			t.Error("expected conflict: term 'ML' already maps to canonical 3, cannot also map to 7")
42		}
43	}
44	
45	func TestSynonymConflict_SameCanonicalAllowed(t *testing.T) {
46		// Pre-existing: "ML" -> canonical tag 3, active
47		existing := []testSynonym{
48			{ID: 1, Term: "ML", CanonicalTagID: 3, Status: "active"},
49		}
50	
51		// Attempt: "ML" -> canonical tag 3 (same tag) — must NOT conflict
52		// (this is an upsert/duplicate, not a conflict)
53		if synonymConflictExists(existing, "ML", 3) {
54			t.Error("should NOT conflict: same term pointing to the same canonical tag is allowed")
55		}
56	}
57	
58	func TestSynonymConflict_InactiveSynonymDoesNotBlock(t *testing.T) {
59		// Pre-existing: "ML" -> canonical tag 3, but INACTIVE (pending_review)
60		existing := []testSynonym{
61			{ID: 1, Term: "ML", CanonicalTagID: 3, Status: "pending_review"},
62		}
63	
64		// Attempt: "ML" -> canonical tag 7 — must NOT conflict (existing is inactive)
65		if synonymConflictExists(existing, "ML", 7) {
66			t.Error("should NOT conflict: existing synonym is not active")
67		}
68	}
69	
70	func TestSynonymConflict_DifferentTermNoConflict(t *testing.T) {
71		// Pre-existing: "ML" -> canonical tag 3, active
72		existing := []testSynonym{
73			{ID: 1, Term: "ML", CanonicalTagID: 3, Status: "active"},
74		}
75	
76		// Attempt: "machine learning" -> canonical tag 7 — NOT a conflict (different term)
77		if synonymConflictExists(existing, "machine learning", 7) {
78			t.Error("should NOT conflict: different term can map to a different canonical tag")
79		}
80	}
81	
82	func TestSynonymConflict_MultipleExistingSynonyms(t *testing.T) {
83		existing := []testSynonym{
84			{ID: 1, Term: "ML", CanonicalTagID: 3, Status: "active"},
85			{ID: 2, Term: "machine learning", CanonicalTagID: 3, Status: "active"},
86			{ID: 3, Term: "AWS", CanonicalTagID: 5, Status: "active"},
87			{ID: 4, Term: "py", CanonicalTagID: 6, Status: "active"},
88		}
89	
90		// "ML" -> 5 conflicts (ML already active for 3)
91		if !synonymConflictExists(existing, "ML", 5) {
92			t.Error("expected conflict: 'ML' active for canonical 3")
93		}
94	
95		// "AWS" -> 5 does NOT conflict (same canonical)
96		if synonymConflictExists(existing, "AWS", 5) {
97			t.Error("should NOT conflict: 'AWS' already mapped to canonical 5")
98		}
99	
100		// "AWS" -> 7 DOES conflict
101		if !synonymConflictExists(existing, "AWS", 7) {
102			t.Error("expected conflict: 'AWS' active for canonical 5, cannot map to 7")
103		}
104	
105		// "terraform" -> 5 does NOT conflict (new term)
106		if synonymConflictExists(existing, "terraform", 5) {
107			t.Error("should NOT conflict: 'terraform' is a new term")
108		}
109	
110		// "py" -> 6 does NOT conflict (same canonical)
111		if synonymConflictExists(existing, "py", 6) {
112			t.Error("should NOT conflict: 'py' already maps to canonical 6")
113		}
114	
115		// "py" -> 3 DOES conflict
116		if !synonymConflictExists(existing, "py", 3) {
117			t.Error("expected conflict: 'py' active for canonical 6, cannot map to 3")
118		}
119	}
120	
121	func TestSynonymConflict_RejectedSynonymDoesNotBlock(t *testing.T) {
122		existing := []testSynonym{
123			{ID: 1, Term: "ML", CanonicalTagID: 3, Status: "rejected"},
124		}
125	
126		if synonymConflictExists(existing, "ML", 7) {
127			t.Error("should NOT conflict: existing synonym was rejected")
128		}
129	}
130	
131	func TestSynonymConflict_MixedStatuses(t *testing.T) {
132		existing := []testSynonym{
133			{ID: 1, Term: "ML", CanonicalTagID: 3, Status: "active"},
134			{ID: 2, Term: "ML", CanonicalTagID: 5, Status: "rejected"},     // rejected: should not count
135			{ID: 3, Term: "ML", CanonicalTagID: 7, Status: "pending_review"}, // pending: should not count
136		}
137	
138		// "ML" -> 5 DOES conflict because ID 1 (active, canonical 3) still blocks it
139		if !synonymConflictExists(existing, "ML", 5) {
140			t.Error("expected conflict: 'ML' has an active mapping to canonical 3")
141		}
142	
143		// "ML" -> 3 does NOT conflict (same canonical as the active one)
144		if synonymConflictExists(existing, "ML", 3) {
145			t.Error("should NOT conflict: mapping to same canonical as active synonym")
146		}
147	}
148	
149	func TestSynonymConflict_EmptyExistingAllowed(t *testing.T) {
150		existing := []testSynonym{}
151	
152		if synonymConflictExists(existing, "anything", 99) {
153			t.Error("should NOT conflict: no existing synonyms")
154		}
155	}
156	
157	func TestSynonymConflict_CaseSensitivity(t *testing.T) {
158		// The PostgreSQL trigger compares term = NEW.term, which is case-sensitive at the DB level.
159		// The backend normalizes to lowercase before inserting (in CreateSynonym).
160		// This test validates that the conflict check is case-sensitive as written.
161		existing := []testSynonym{
162			{ID: 1, Term: "ml", CanonicalTagID: 3, Status: "active"},
163		}
164	
165		// Same term, different case — the Go logic does exact match
166		if synonymConflictExists(existing, "ML", 7) {
167			t.Error("exact-match logic: 'ML' != 'ml', no conflict at logic level (normalization happens at insert)")
168		}
169	
170		// Same case — DOES conflict
171		if !synonymConflictExists(existing, "ml", 7) {
172			t.Error("expected conflict: 'ml' exact match with active synonym for different canonical")
173		}
174	}
