41	// --- AppVersionCheck grace-period middleware behavior tests ---
42	// These use inline middleware stubs that replicate the exact logic from
43	// AppVersionCheck so the tests run without a DB or real config service.
44	
45	// versionCheckMiddleware replicates AppVersionCheck logic with injected params.
46	func versionCheckMiddleware(minVersion string, minVersionSetAt time.Time, graceDays int) echo.MiddlewareFunc {
47		return func(next echo.HandlerFunc) echo.HandlerFunc {
48			return func(c echo.Context) error {
49				v := c.Request().Header.Get("X-App-Version")
50				if v == "" {
51					return next(c)
52				}
53				if compareVersions(v, minVersion) < 0 {
54					graceDeadline := minVersionSetAt.Add(time.Duration(graceDays) * 24 * time.Hour)
55					withinGrace := time.Now().Before(graceDeadline)
56	
57					c.Response().Header().Set("X-App-Deprecated", "true")
58					c.Response().Header().Set("X-Min-Version", minVersion)
59	
60					if !withinGrace {
61						return echo.NewHTTPError(http.StatusUpgradeRequired,
62							"client version unsupported and grace period expired; upgrade to "+minVersion+" or later")
63					}
64	
65					c.Set("read_only", true)
66					method := c.Request().Method
67					if method == "POST" || method == "PUT" || method == "PATCH" || method == "DELETE" {
68						return echo.NewHTTPError(http.StatusUpgradeRequired, "read-only during grace period")
69					}
70				}
71				return next(c)
72			}
73		}
74	}
