)

func TestParseCronInterval_EveryNMinutes(t *testing.T) {
	tests := []struct {
		expr     string
		expected time.Duration
	}{
		{"*/5 * * * *", 5 * time.Minute},
		{"*/15 * * * *", 15 * time.Minute},
		{"*/1 * * * *", 1 * time.Minute},
		{"*/60 * * * *", 60 * time.Minute},
	}

	for _, tt := range tests {
		result := parseCronInterval(tt.expr)
		if result != tt.expected {
			t.Errorf("parseCronInterval(%q) = %v, want %v", tt.expr, result, tt.expected)
		}
	}
}

func TestParseCronInterval_DailyJob(t *testing.T) {
