8	// classifyVariance is the pure variance classification logic extracted from
9	// ReconciliationService.CompareStatement for direct unit testing.
10	// It mirrors the exact logic in reconciliation.go lines 54-63.
11	func classifyVariance(invoiceAmount, orderAmount, threshold float64) (suggestedState string, autoWriteoff bool) {
12		variance := invoiceAmount - orderAmount
13		absVariance := math.Abs(variance)
14	
15		autoWriteoff = absVariance < threshold && absVariance > 0
16		suggestedState = "matched"
17		if absVariance > 0 {
18			if absVariance < threshold {
19				suggestedState = "pending_approval"
20			} else {
21				suggestedState = "manual_investigation"
22			}
23		}
24		return
25	}
