func TestIntegration_ContentHashTrigger_AutoGeneratesHash(t *testing.T) {
	db := getTestDB(t)
	defer db.Close()
	ctx := context.Background()

	slug := fmt.Sprintf("hash-trigger-test-%d", os.Getpid())

