// TestCheckFlag_PassesUserContext verifies that the CheckFlag handler correctly passes
// user_id and role_ids from JWT claims to the flag evaluation logic.
func TestCheckFlag_PassesUserContext(t *testing.T) {
	// Create a config service with a role-based flag that only allows role ID 3 (learner)
	svc := &services.ConfigService{}
	// We need to use the test constructor to inject flags
	flagSvc := services.NewConfigServiceForTest(map[string]models.Config{})

	// Manually set a flag - need to access via the exported method
	// Instead, create a handler with a real ConfigService using test data
	_ = svc
	_ = flagSvc

	// Use a simpler approach: test the handler wiring by confirming it reads context values
	e := echo.New()

	// Create a ConfigService with a role_based flag
