3	import (
4		"crypto/aes"
5		"crypto/cipher"
6		"crypto/rand"
7		"encoding/hex"
8		"errors"
9		"io"
10		"os"
11	)
12	
13	var encryptionKey []byte
14	
15	func InitEncryptionKey() error {
16		keyHex := os.Getenv("AES_ENCRYPTION_KEY")
17		if keyHex == "" {
18			return errors.New("AES_ENCRYPTION_KEY environment variable is required")
19		}
20		key, err := hex.DecodeString(keyHex)
21		if err != nil {
22			return errors.New("AES_ENCRYPTION_KEY must be a valid hex string")
23		}
24		if len(key) != 32 {
25			return errors.New("AES_ENCRYPTION_KEY must be 64 hex characters (32 bytes for AES-256)")
26		}
27		encryptionKey = key
28		return nil
29	}
30	
31	// Encrypt encrypts plaintext using AES-256-GCM.
32	// Returns ciphertext with the nonce prepended.
33	func Encrypt(plaintext []byte) ([]byte, error) {
34		if len(encryptionKey) == 0 {
35			return nil, errors.New("encryption key not initialized")
36		}
37	
38		block, err := aes.NewCipher(encryptionKey)
39		if err != nil {
40			return nil, err
41		}
42	
43		aesGCM, err := cipher.NewGCM(block)
44		if err != nil {
45			return nil, err
46		}
47	
48		nonce := make([]byte, aesGCM.NonceSize())
49		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
50			return nil, err
51		}
52	
53		ciphertext := aesGCM.Seal(nonce, nonce, plaintext, nil)
54		return ciphertext, nil
55	}
56	
57	// Decrypt decrypts ciphertext produced by Encrypt (nonce-prepended AES-256-GCM).
58	func Decrypt(ciphertext []byte) ([]byte, error) {
59		if len(encryptionKey) == 0 {
60			return nil, errors.New("encryption key not initialized")
61		}
62	
63		block, err := aes.NewCipher(encryptionKey)
64		if err != nil {
65			return nil, err
66		}
67	
68		aesGCM, err := cipher.NewGCM(block)
69		if err != nil {
70			return nil, err
71		}
72	
73		nonceSize := aesGCM.NonceSize()
74		if len(ciphertext) < nonceSize {
75			return nil, errors.New("ciphertext too short")
76		}
77	
78		nonce, ciphertextBody := ciphertext[:nonceSize], ciphertext[nonceSize:]
79		plaintext, err := aesGCM.Open(nil, nonce, ciphertextBody, nil)
80		if err != nil {
81			return nil, err
82		}
83	
84		return plaintext, nil
85	}
86	
87	// EncryptString is a convenience wrapper for string data.
88	func EncryptString(plaintext string) ([]byte, error) {
89		return Encrypt([]byte(plaintext))
90	}
91	
92	// DecryptString is a convenience wrapper that returns a string.
93	func DecryptString(ciphertext []byte) (string, error) {
94		b, err := Decrypt(ciphertext)
95		if err != nil {
96			return "", err
97		}
98		return string(b), nil
99	}
